(2, 'acceptance_form', 'Student TP Acceptance Form', 'Teaching Practice Acceptance Form for Federal University of Kashere with discipline checkboxes', '<p style=\"line-height: 1.75; text-align: right;\"><span style=\"font-size: 18px;\"><span>{today}</span></span></p><p style=\"line-height: 1.5; text-align: left;\"><span style=\"font-size: 18px;\"><span><strong>Name of School:</strong><br>................................................................................................</span></span></p><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>Sir/Madam,</span></span></p><h2 style=\"text-align: center;\"><span style=\"font-size: 18px;\"><span><strong>STUDENT TEACHING PRACTICE ACCEPTANCE FORM FOR {current_session} EXERCISE</strong></span></span></h2><p style=\"text-align: center;\"></p><h3 style=\"text-align: justify;\"><span style=\"font-size: 18px;\"><span>a. STUDENT DETAILS</span></span></h3><ul><li><p style=\"line-height: 1; text-align: justify;\"><span style=\"font-size: 18px;\"><span><strong>Student Name:</strong> {student_name}</span></span></p></li><li><p style=\"line-height: 1; text-align: justify;\"><span style=\"font-size: 18px;\"><span><strong>Registration Number:</strong> {student_regno}</span></span></p></li><li><p style=\"line-height: 1; text-align: justify;\"><span style=\"font-size: 18px;\"><span><strong>Discipline:</strong> {student_program}</span></span></p></li><li><p style=\"line-height: 1; text-align: justify;\"><span style=\"font-size: 18px;\"><span><strong>Institution:</strong> {institution_name}</span></span></p></li></ul><p style=\"line-height: 1; text-align: justify;\"></p><h3 style=\"text-align: justify;\"><span style=\"font-size: 18px;\"><span>b. ACCEPTANCE STATEMENT</span></span></h3><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>This is to certify that the above-named student, who presented an <strong>official Introduction Letter</strong> from <strong>{institution_name}</strong>, has been <strong>accepted</strong> to carry out the Teaching Practice exercise in our school for the period stated above.</span></span></p><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>The student will be allowed to participate in teaching and other relevant academic activities under supervision, in accordance with the rules and regulations of the school.</span></span></p><p style=\"line-height: 1.75; text-align: justify;\"></p><p style=\"line-height: 1.75; text-align: justify;\"></p><p style=\"line-height: 1.75; text-align: justify;\"></p><p style=\"line-height: 1; text-align: justify;\"><span style=\"font-size: 18px;\"><span>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></span><span style=\"font-size: 10px;\"><span>..............................................................................................................&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; ........................................................................................</span></span><span style=\"font-size: 18px;\"><span><br>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Name/rank of officer in-Charge&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Signature/Official Stamp</span></span></p><p style=\"line-height: 1; text-align: justify;\"></p><p style=\"line-height: 1; text-align: justify;\"><span style=\"font-size: 18px;\"><span>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></span><span style=\"font-size: 10px;\"><span>.........................................................&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; </span></span><span style=\"font-size: 18px;\"><span><br>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Date&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></span></p><p style=\"line-height: 1; text-align: justify;\"></p><p style=\"line-height: 1; text-align: justify;\"></p><p></p>', '.hr-line { border-top: 2px solid #000; margin-bottom: 20px; }\r\n.fs { font-size: 14px; }\r\n.float-right { float: right; }\r\n.text-center { text-align: center; }\r\n.fw-bold { font-weight: bold; }\r\n.letter-subject { font-size: 16px; text-transform: uppercase; }\r\n.pt-3 { padding-top: 15px; }\r\n.p-1 { padding: 5px; }\r\n.mt-5 { margin-top: 40px; }\r\n.row { display: flex; flex-wrap: wrap; }\r\n.col-6 { width: 50%; }\r\nol { padding-left: 20px; }\r\nul { list-style-type: none; padding-left: 0; }', NULL, NULL, 'A4', 'portrait', NULL, 'published', 29, '2025-12-30 13:21:11', 1, NULL, NULL, 0, NULL, 1, 1, '2025-12-30 13:21:11', '2026-01-20 16:42:40');
