(2, 'introduction_letter', 'TP Introduction Letter', 'Request for Student Placement Letter for Federal University of Kashere - NUC Bachelor\'s Degree requirements', '<p style=\"text-align: right;\"><span style=\"font-size: 18px;\"><span>{today}</span></span></p><p style=\"line-height: 1;\"><span style=\"font-size: 18px;\"><span>The Principal/Head Teacher,</span></span></p><p style=\"line-height: 1;\"><span style=\"font-size: 18px;\"><span>_____________________________________________</span></span></p><p style=\"line-height: 1;\"><span style=\"font-size: 18px;\"><span>_____________________________________________</span></span></p><p style=\"line-height: 1.5;\"><span style=\"font-size: 18px;\"><span>Sir/Madam,</span></span></p><h3 style=\"line-height: 1.5; text-align: center;\"><span style=\"font-size: 20px;\"><span><strong>REQUEST FOR PLACEMENT OF STUDENT FOR THE {current_session} TEACHING PRACTICE EXERCISE</strong></span></span></h3><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>I am writing to request your kind consideration in offering a place of attachment for the <strong>{current_session}</strong> Student Teaching Practice exercise. The bearer of this letter, Mr./Mrs./Miss <strong>{student_name}</strong> with Registration Number <strong>{student_regno}</strong> is a student at our esteemed institution, majoring in <strong>{student_program}</strong>, and is required to undertake a Teaching Practice exercise as part of the requirements set by the National Universities Commission (NUC) for the award of a Bachelor\'s Degree in Education.</span></span></p><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>We would be grateful if your school could accommodate the student for this critical component of their academic training. We also kindly request that you monitor and guide the student to support his/her professional growth and development.</span></span></p><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>We are confident that our student will adhere to all rules and regulations of your school. However, any instances of misconduct on the part of the student should be reported to the University so that appropriate action can be taken.</span></span></p><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>We therefore, request you to please confirm his/her acceptance by signing on the attached form.</span></span></p><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>Thank you for your usual cooperation.</span></span></p><p><span style=\"font-size: 18px;\"><span>﻿</span></span><img src=\"data:image/png;base64,\" width=\"168\" height=\"42\" style=\"width: 168px; height: 42px;\"></p><p style=\"line-height: 0.5;\"><span style=\"font-size: 18px;\"><span>{coordinator_name}</span></span></p><p style=\"line-height: 0.5;\"><strong>Teaching Practice Coordinator</strong></p><p style=\"line-height: 0.5;\"><span style=\"font-size: 18px;\"><span>{coordinator_phone}</span></span></p>', '.hr-line { border-top: 2px solid #000; margin-bottom: 20px; }\r\n.fs { font-size: 14px; line-height: 1.6; }\r\n.float-right { float: right; }\r\n.text-center { text-align: center; }\r\n.text-l { font-size: 14px; }\r\n.fw-bold { font-weight: bold; }\r\n.letter-subject { font-size: 16px; text-transform: uppercase; margin: 20px 0; }\r\n.signature-area { margin-top: 40px; }\r\n.signature-area img { height: 60px; }\r\np { margin-bottom: 15px; }', NULL, NULL, 'A4', 'portrait', NULL, 'published', 43, '2025-12-31 17:01:06', 1, NULL, NULL, 0, NULL, 1, 1, '2025-12-30 13:21:11', '2025-12-31 17:01:06');
INSERT INTO document_templates (institution_id, document_type, name, description, content, css_styles, header_content, footer_content, page_size, page_orientation, page_margins, status, version, published_at, published_by, applicable_institution_types, applicable_program_ids, is_session_specific, session_id, is_default, created_by, created_at, updated_at) VALUES
(2, 'posting_letter', 'TP Posting Letter', 'Official Posting Letter for students to take to their teaching practice school', '<p style=\"text-align: right;\"><span style=\"font-size: 18px;\"><span>{posting_date}</span></span></p><p><span style=\"font-size: 18px;\"><span>The Principal,<br>{school_name}.</span></span></p><p><span style=\"font-size: 18px;\"><span>Sir,</span></span></p><h2 style=\"text-align: center;\"><span style=\"font-size: 18px;\"><span>POSTING LETTER FOR {current_session} TEACHING PRACTICE EXERCISE</span></span></h2><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>This letter serves to formally introduce <strong>{student_name}</strong> (Registration No.: <strong>{student_regno}</strong>), a student-teacher from our institution, who has been assigned to undertake the mandatory Teaching Practice exercise at your esteemed school. The exercise is pre-requisite of the award of Bachelor\'s Degree in Education, and we sincerely appreciate your cooperation in facilitating this pedagogical training.</span></span></p><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>The exercise shall span a period of {tp_duration}, commencing on <strong>{tp_start_date}</strong> and concluding on <strong>{tp_end_date}</strong>. In accordance with the revised curriculum, the assessment of the student-teacher will be conducted jointly by the University and your school. The assessment forms have been provided for your use. We kindly request that evaluations be completed every three (3) weeks and submitted to our visiting supervisors for institutional assessment. All assessments shall be treated with strict confidentiality.</span></span></p><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>We recommend that the student-teacher be actively engaged in both academic and extracurricular activities, including but not limited to classroom instruction, pastoral duties, and ancillary school functions. This comprehensive exposure is designed to enhance their professional development.</span></span></p><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>The University deeply values and appreciate your continued partnership in our collective mission to nurture competent educators for the academic community.</span></span></p><p><span style=\"font-size: 18px;\"><span>Thank you.</span></span></p><p><span style=\"font-size: 18px;\"><span>﻿</span></span><img src=\"data:image/png;base64,\" width=\"168\" height=\"42\" style=\"width: 168px; height: 42px;\"></p><p style=\"line-height: 0.5;\"><span style=\"font-size: 18px;\"><span>{coordinator_name}</span></span></p><p style=\"line-height: 0.5;\"><strong>Teaching Practice Coordinator</strong></p>', '.hr-line { border-top: 2px solid #000; margin-bottom: 20px; }\r\n.fs { font-size: 14px; line-height: 1.6; }\r\n.float-right { float: right; }\r\n.text-center { text-align: center; }\r\n.text-l { font-size: 14px; }\r\n.fw-bold { font-weight: bold; }\r\n.mt-2 { margin-top: 10px; }\r\n.signature-area { margin-top: 40px; }\r\n.signature-area img { height: 70px; }\r\np { margin-bottom: 15px; }', NULL, NULL, 'A4', 'portrait', NULL, 'published', 11, '2025-12-30 13:21:11', 1, NULL, NULL, 0, NULL, 1, 1, '2025-12-30 13:21:11', '2026-01-20 17:48:36');
INSERT INTO document_templates (institution_id, document_type, name, description, content, css_styles, header_content, footer_content, page_size, page_orientation, page_margins, status, version, published_at, published_by, applicable_institution_types, applicable_program_ids, is_session_specific, session_id, is_default, created_by, created_at, updated_at) VALUES
(2, 'supervisor_invitation_letter', 'Supervisor Invitation Letter', 'Invitation letter for posting supervisor to students.', '<p style=\"text-align: right;\"><span style=\"font-size: 20px;\"><span>{today_date}</span></span></p><p></p><p><span style=\"font-size: 20px;\"><span>Dear {supervisor_name},</span></span></p><h1 style=\"line-height: 1.4; text-align: center;\"><span style=\"font-size: 20px;\"><span><strong>INVITATION FOR {current_session}&nbsp;TEACHING PRACTICE EXERCISE</strong></span></span></h1><p style=\"line-height: 1.82; text-align: justify;\"><span style=\"font-size: 20px;\"><span>The Directorate is pleased to invite you to participate in the Teaching Practice Supervision exercise for the {current_session} session. This invitation is extended in recognition of your qualifications and eligibility to supervise student teachers effectively.</span></span></p><p style=\"line-height: 1.82; text-align: justify;\"><span style=\"font-size: 20px;\"><span>We look forward to your valuable contribution to this critical academic activity.</span></span></p><p style=\"line-height: 1.15; text-align: justify;\"><span style=\"font-size: 20px;\"><span>Please accept the Directorate\'s best regards.</span></span></p><p style=\"line-height: 1.15; text-align: justify;\"><br></p><p style=\"line-height: 1.15; text-align: justify;\"></p><p style=\"line-height: 1.15; text-align: justify;\"></p><p style=\"line-height: 1.5; text-align: justify;\"><br><img src=\"https://fcetgombe.sistpms.com/assets/img/ess_signature.jpg\" alt=\"Sign Dr. Abdulkadir Abdulrahman\" width=\"149\" height=\"45\" style=\"width: 149px; height: 45px;\"><br><span style=\"color: rgb(0, 0, 0); font-size: 20px;\"><span>{coordinator_name}</span></span><span style=\"font-size: 20px;\"><span><br></span></span><span style=\"color: rgb(0, 0, 0); font-size: 20px;\"><span><strong>Deputy Director T.P</strong></span></span></p><p style=\"line-height: 1.82; text-align: justify;\"></p><p style=\"line-height: 1.82; text-align: justify;\"></p><p style=\"line-height: 1.82; text-align: justify;\"></p><p style=\"line-height: 1.82; text-align: justify;\"></p><p style=\"line-height: 1.82; text-align: justify;\"></p><p style=\"line-height: 1.82; text-align: justify;\"></p><p style=\"line-height: 1.82; text-align: justify;\"></p><p style=\"line-height: 1.82; text-align: justify;\"></p><p style=\"line-height: 1.82; text-align: justify;\"></p><p style=\"line-height: 1.82; text-align: justify;\"></p>', NULL, NULL, NULL, 'A4', 'portrait', NULL, 'published', 15, '2026-01-20 17:37:59', 1, NULL, NULL, 0, NULL, 0, 1, '2026-01-20 17:37:59', '2026-01-20 18:23:16');
INSERT INTO document_templates (institution_id, document_type, name, description, content, css_styles, header_content, footer_content, page_size, page_orientation, page_margins, status, version, published_at, published_by, applicable_institution_types, applicable_program_ids, is_session_specific, session_id, is_default, created_by, created_at, updated_at) VALUES
(3, 'acceptance_form', 'Student TP Acceptance Form', 'Teaching Practice Acceptance Form for Federal University of Kashere with discipline checkboxes', '<p style=\"line-height: 1.75; text-align: right;\"><span style=\"font-size: 18px;\"><span>{today}</span></span></p><p style=\"line-height: 1.5; text-align: left;\"><span style=\"font-size: 18px;\"><span><strong>Name of School:</strong><br>................................................................................................</span></span></p><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>Sir/Madam,</span></span></p><h2 style=\"text-align: center;\"><span style=\"font-size: 18px;\"><span><strong>STUDENT TEACHING PRACTICE ACCEPTANCE FORM FOR {current_session} EXERCISE</strong></span></span></h2><p style=\"text-align: center;\"></p><h3 style=\"text-align: justify;\"><span style=\"font-size: 18px;\"><span>a. STUDENT DETAILS</span></span></h3><ul><li><p style=\"line-height: 1; text-align: justify;\"><span style=\"font-size: 18px;\"><span><strong>Student Name:</strong> {student_name}</span></span></p></li><li><p style=\"line-height: 1; text-align: justify;\"><span style=\"font-size: 18px;\"><span><strong>Registration Number:</strong> {student_regno}</span></span></p></li><li><p style=\"line-height: 1; text-align: justify;\"><span style=\"font-size: 18px;\"><span><strong>Discipline:</strong> {student_program}</span></span></p></li><li><p style=\"line-height: 1; text-align: justify;\"><span style=\"font-size: 18px;\"><span><strong>Institution:</strong> {institution_name}</span></span></p></li></ul><p style=\"line-height: 1; text-align: justify;\"></p><h3 style=\"text-align: justify;\"><span style=\"font-size: 18px;\"><span>b. ACCEPTANCE STATEMENT</span></span></h3><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>This is to certify that the above-named student, who presented an <strong>official Introduction Letter</strong> from <strong>{institution_name}</strong>, has been <strong>accepted</strong> to carry out the Teaching Practice exercise in our school for the period stated above.</span></span></p><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>The student will be allowed to participate in teaching and other relevant academic activities under supervision, in accordance with the rules and regulations of the school.</span></span></p><p style=\"line-height: 1.75; text-align: justify;\"></p><p style=\"line-height: 1.75; text-align: justify;\"></p><p style=\"line-height: 1.75; text-align: justify;\"></p><p style=\"line-height: 1; text-align: justify;\"><span style=\"font-size: 18px;\"><span>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></span><span style=\"font-size: 10px;\"><span>..............................................................................................................&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; ........................................................................................</span></span><span style=\"font-size: 18px;\"><span><br>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Name/rank of officer in-Charge&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Signature/Official Stamp</span></span></p><p style=\"line-height: 1; text-align: justify;\"></p><p style=\"line-height: 1; text-align: justify;\"><span style=\"font-size: 18px;\"><span>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></span><span style=\"font-size: 10px;\"><span>.........................................................&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; </span></span><span style=\"font-size: 18px;\"><span><br>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Date&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></span></p><p style=\"line-height: 1; text-align: justify;\"></p><p style=\"line-height: 1; text-align: justify;\"></p><p></p>', '.hr-line { border-top: 2px solid #000; margin-bottom: 20px; }\r\n.fs { font-size: 14px; }\r\n.float-right { float: right; }\r\n.text-center { text-align: center; }\r\n.fw-bold { font-weight: bold; }\r\n.letter-subject { font-size: 16px; text-transform: uppercase; }\r\n.pt-3 { padding-top: 15px; }\r\n.p-1 { padding: 5px; }\r\n.mt-5 { margin-top: 40px; }\r\n.row { display: flex; flex-wrap: wrap; }\r\n.col-6 { width: 50%; }\r\nol { padding-left: 20px; }\r\nul { list-style-type: none; padding-left: 0; }', NULL, NULL, 'A4', 'portrait', NULL, 'published', 29, '2025-12-30 13:21:11', 1, NULL, NULL, 0, NULL, 1, 1, '2025-12-30 13:21:11', '2026-01-20 16:42:40');
INSERT INTO document_templates (institution_id, document_type, name, description, content, css_styles, header_content, footer_content, page_size, page_orientation, page_margins, status, version, published_at, published_by, applicable_institution_types, applicable_program_ids, is_session_specific, session_id, is_default, created_by, created_at, updated_at) VALUES
(3, 'introduction_letter', 'TP Introduction Letter', 'Request for Student Placement Letter for Federal University of Kashere - NUC Bachelor\'s Degree requirements', '<p style=\"text-align: right;\"><span style=\"font-size: 18px;\"><span>{today}</span></span></p><p style=\"line-height: 1;\"><span style=\"font-size: 18px;\"><span>The Principal/Head Teacher,</span></span></p><p style=\"line-height: 1;\"><span style=\"font-size: 18px;\"><span>_____________________________________________</span></span></p><p style=\"line-height: 1;\"><span style=\"font-size: 18px;\"><span>_____________________________________________</span></span></p><p style=\"line-height: 1.5;\"><span style=\"font-size: 18px;\"><span>Sir/Madam,</span></span></p><h3 style=\"line-height: 1.5; text-align: center;\"><span style=\"font-size: 20px;\"><span><strong>REQUEST FOR PLACEMENT OF STUDENT FOR THE {current_session} TEACHING PRACTICE EXERCISE</strong></span></span></h3><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>I am writing to request your kind consideration in offering a place of attachment for the <strong>{current_session}</strong> Student Teaching Practice exercise. The bearer of this letter, Mr./Mrs./Miss <strong>{student_name}</strong> with Registration Number <strong>{student_regno}</strong> is a student at our esteemed institution, majoring in <strong>{student_program}</strong>, and is required to undertake a Teaching Practice exercise as part of the requirements set by the National Universities Commission (NUC) for the award of a Bachelor\'s Degree in Education.</span></span></p><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>We would be grateful if your school could accommodate the student for this critical component of their academic training. We also kindly request that you monitor and guide the student to support his/her professional growth and development.</span></span></p><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>We are confident that our student will adhere to all rules and regulations of your school. However, any instances of misconduct on the part of the student should be reported to the University so that appropriate action can be taken.</span></span></p><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>We therefore, request you to please confirm his/her acceptance by signing on the attached form.</span></span></p><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>Thank you for your usual cooperation.</span></span></p><p><span style=\"font-size: 18px;\"><span>﻿</span></span><img src=\"data:image/png;base64,\" width=\"168\" height=\"42\" style=\"width: 168px; height: 42px;\"></p><p style=\"line-height: 0.5;\"><span style=\"font-size: 18px;\"><span>{coordinator_name}</span></span></p><p style=\"line-height: 0.5;\"><strong>Teaching Practice Coordinator</strong></p><p style=\"line-height: 0.5;\"><span style=\"font-size: 18px;\"><span>{coordinator_phone}</span></span></p>', '.hr-line { border-top: 2px solid #000; margin-bottom: 20px; }\r\n.fs { font-size: 14px; line-height: 1.6; }\r\n.float-right { float: right; }\r\n.text-center { text-align: center; }\r\n.text-l { font-size: 14px; }\r\n.fw-bold { font-weight: bold; }\r\n.letter-subject { font-size: 16px; text-transform: uppercase; margin: 20px 0; }\r\n.signature-area { margin-top: 40px; }\r\n.signature-area img { height: 60px; }\r\np { margin-bottom: 15px; }', NULL, NULL, 'A4', 'portrait', NULL, 'published', 43, '2025-12-31 17:01:06', 1, NULL, NULL, 0, NULL, 1, 1, '2025-12-30 13:21:11', '2025-12-31 17:01:06');
INSERT INTO document_templates (institution_id, document_type, name, description, content, css_styles, header_content, footer_content, page_size, page_orientation, page_margins, status, version, published_at, published_by, applicable_institution_types, applicable_program_ids, is_session_specific, session_id, is_default, created_by, created_at, updated_at) VALUES
(3, 'posting_letter', 'TP Posting Letter', 'Official Posting Letter for students to take to their teaching practice school', '<p style=\"text-align: right;\"><span style=\"font-size: 18px;\"><span>{posting_date}</span></span></p><p><span style=\"font-size: 18px;\"><span>The Principal,<br>{school_name}.</span></span></p><p><span style=\"font-size: 18px;\"><span>Sir,</span></span></p><h2 style=\"text-align: center;\"><span style=\"font-size: 18px;\"><span>POSTING LETTER FOR {current_session} TEACHING PRACTICE EXERCISE</span></span></h2><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>This letter serves to formally introduce <strong>{student_name}</strong> (Registration No.: <strong>{student_regno}</strong>), a student-teacher from our institution, who has been assigned to undertake the mandatory Teaching Practice exercise at your esteemed school. The exercise is pre-requisite of the award of Bachelor\'s Degree in Education, and we sincerely appreciate your cooperation in facilitating this pedagogical training.</span></span></p><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>The exercise shall span a period of {tp_duration}, commencing on <strong>{tp_start_date}</strong> and concluding on <strong>{tp_end_date}</strong>. In accordance with the revised curriculum, the assessment of the student-teacher will be conducted jointly by the University and your school. The assessment forms have been provided for your use. We kindly request that evaluations be completed every three (3) weeks and submitted to our visiting supervisors for institutional assessment. All assessments shall be treated with strict confidentiality.</span></span></p><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>We recommend that the student-teacher be actively engaged in both academic and extracurricular activities, including but not limited to classroom instruction, pastoral duties, and ancillary school functions. This comprehensive exposure is designed to enhance their professional development.</span></span></p><p style=\"line-height: 1.75; text-align: justify;\"><span style=\"font-size: 18px;\"><span>The University deeply values and appreciate your continued partnership in our collective mission to nurture competent educators for the academic community.</span></span></p><p><span style=\"font-size: 18px;\"><span>Thank you.</span></span></p><p><span style=\"font-size: 18px;\"><span>﻿</span></span><img src=\"data:image/png;base64,\" width=\"168\" height=\"42\" style=\"width: 168px; height: 42px;\"></p><p style=\"line-height: 0.5;\"><span style=\"font-size: 18px;\"><span>{coordinator_name}</span></span></p><p style=\"line-height: 0.5;\"><strong>Teaching Practice Coordinator</strong></p>', '.hr-line { border-top: 2px solid #000; margin-bottom: 20px; }\r\n.fs { font-size: 14px; line-height: 1.6; }\r\n.float-right { float: right; }\r\n.text-center { text-align: center; }\r\n.text-l { font-size: 14px; }\r\n.fw-bold { font-weight: bold; }\r\n.mt-2 { margin-top: 10px; }\r\n.signature-area { margin-top: 40px; }\r\n.signature-area img { height: 70px; }\r\np { margin-bottom: 15px; }', NULL, NULL, 'A4', 'portrait', NULL, 'published', 11, '2025-12-30 13:21:11', 1, NULL, NULL, 0, NULL, 1, 1, '2025-12-30 13:21:11', '2026-01-20 17:48:36');
