(3, 'supervisor_invitation_letter', 'Supervisor Invitation Letter', 'Invitation letter for posting supervisor to students.', '<p style=\"text-align: right;\"><span style=\"font-size: 20px;\"><span>{today_date}</span></span></p><p></p><p><span style=\"font-size: 20px;\"><span>Dear {supervisor_name},</span></span></p><h1 style=\"line-height: 1.4; text-align: center;\"><span style=\"font-size: 20px;\"><span><strong>INVITATION FOR {current_session}&nbsp;TEACHING PRACTICE EXERCISE</strong></span></span></h1><p style=\"line-height: 1.82; text-align: justify;\"><span style=\"font-size: 20px;\"><span>The Directorate is pleased to invite you to participate in the Teaching Practice Supervision exercise for the {current_session} session. This invitation is extended in recognition of your qualifications and eligibility to supervise student teachers effectively.</span></span></p><p style=\"line-height: 1.82; text-align: justify;\"><span style=\"font-size: 20px;\"><span>We look forward to your valuable contribution to this critical academic activity.</span></span></p><p style=\"line-height: 1.15; text-align: justify;\"><span style=\"font-size: 20px;\"><span>Please accept the Directorate\'s best regards.</span></span></p><p style=\"line-height: 1.15; text-align: justify;\"><br></p><p style=\"line-height: 1.15; text-align: justify;\"></p><p style=\"line-height: 1.15; text-align: justify;\"></p><p style=\"line-height: 1.5; text-align: justify;\"><br><img src=\"https://fcetgombe.sistpms.com/assets/img/ess_signature.jpg\" alt=\"Sign Dr. Abdulkadir Abdulrahman\" width=\"149\" height=\"45\" style=\"width: 149px; height: 45px;\"><br><span style=\"color: rgb(0, 0, 0); font-size: 20px;\"><span>{coordinator_name}</span></span><span style=\"font-size: 20px;\"><span><br></span></span><span style=\"color: rgb(0, 0, 0); font-size: 20px;\"><span><strong>Deputy Director T.P</strong></span></span></p><p style=\"line-height: 1.82; text-align: justify;\"></p><p style=\"line-height: 1.82; text-align: justify;\"></p><p style=\"line-height: 1.82; text-align: justify;\"></p><p style=\"line-height: 1.82; text-align: justify;\"></p><p style=\"line-height: 1.82; text-align: justify;\"></p><p style=\"line-height: 1.82; text-align: justify;\"></p><p style=\"line-height: 1.82; text-align: justify;\"></p><p style=\"line-height: 1.82; text-align: justify;\"></p><p style=\"line-height: 1.82; text-align: justify;\"></p><p style=\"line-height: 1.82; text-align: justify;\"></p>', NULL, NULL, NULL, 'A4', 'portrait', NULL, 'published', 15, '2026-01-20 17:37:59', 1, NULL, NULL, 0, NULL, 0, 1, '2026-01-20 17:37:59', '2026-01-20 18:23:16');
